import{_ as t,o,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"30. Consultation","description":"","frontmatter":{"title":"30. Consultation","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","parental-leave","consultation","union-matters"]},"headers":[],"relativePath":"ebas/mspp/employment/30-consultation.md","filePath":"ebas/mspp/employment/30-consultation.md"}'),r={name:"ebas/mspp/employment/30-consultation.md"};function i(a,e,p,l,c,g){return o(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_30-consultation" tabindex="-1">30. Consultation <a class="header-anchor" href="#_30-consultation" aria-label="Permalink to &quot;30. Consultation&quot;">​</a></h1><p>Nothing in this clause 30 limits the Employer’s obligations to consult with HSRs under the OHS Act.</p><p><strong>30.1</strong> Consultation regarding Major Change</p><p><strong>a.</strong> Where an Employer proposes a Major Change that may have a Significant Effect on an Employee or Employees, the Employer will consult with the Affected Employee/s, and Union, and the Employee’s other chosen representative (where relevant) before any proposed change occurs.</p><p><strong>b.</strong> Consultation will include those who are absent on leave including on workers’ compensation or parental leave.</p><p><strong>c.</strong> The Employer will take reasonable steps to ensure Employees, HSRs (where relevant) and the Union can participate effectively in the Consultation process.</p><p><strong>d.</strong> An employer will provide reasonable resources (ie paid time for Union representatives, access to email, photocopying and meeting rooms) necessary to ensure that Employees and Union representatives can participate effectively in the consultation process.</p><p><strong>e.</strong> Major Change includes (but is not limited to) technological change as defined and referred to at subclause 30.2c below.</p><p><strong>30.2</strong> Definitions Under this clause 30:</p><p><strong>a.</strong> Consultation means a genuine opportunity to influence the decision maker, but not joint decision making. It is not merely an announcement as to what is about to happen.</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p>Consultation includes an opportunity for affected Employees and the Union to provide written and verbal responses including alternative proposals to mitigate or avert any adverse impact on an Affected Employee. Consultation includes the timely provision of all relevant information and response.</p><p><strong>b.</strong> Affected Employee means an Employee on whom a Major Change may have a Significant Effect.</p><p><strong>c.</strong> Major Change means a change in the Employer’s program, production, organisation (including workforce size), physical workplace, workplace arrangements, structure or technology that is likely to have a Significant Effect on Employees.</p><p><strong>d.</strong> Significant Effect includes but is not limited to any of the following:</p><p><strong>(i)</strong> termination of employment;</p><p><strong>(ii)</strong> changes in the size, composition or operation of the Employer’s workforce (including from outsourcing or contracting out a service or or a service the Employer does not perform, or sendouts in pathology services) or skills required;</p><p><strong>(iii)</strong> alteration of the number of hours worked and/or reduction in remuneration;</p><p><strong>(iv)</strong> changes to an Employee’s classification, position description, duties or reporting lines;</p><p><strong>(v)</strong> the need for retraining or relocation/redeployment/transfer to another site or to other work;</p><p><strong>(vi)</strong> removal of an existing amenity;</p><p><strong>(vii)</strong> the removal or reduction of job opportunities, promotion opportunities or job tenure;</p><p><strong>(viii)</strong> changes to shifts / rosters arising from the organisation change</p><p><strong>(ix)</strong> impacts on the workload of an Employee;</p><p><strong>e.</strong> Measures to mitigate or avert may include but are not limited to:</p><p><strong>(i)</strong> redeployment;</p><p><strong>(ii)</strong> retraining, including for a position outside an Employee’s current discipline/classification or scope of practice;</p><p><strong>(iii)</strong> salary maintenance;</p><p><strong>(iv)</strong> job sharing; and / or</p><p><strong>(v)</strong> maintenance of accruals.</p><p><strong>f.</strong> Technological Change means the introduction, alteration or replacement of pharmaceutical or scientific instruments, computers, or work practices ancillary to the use of such equipment, which change, if implemented by an Employer, may have material effects in or on the employment of persons to which this Agreement applies.</p><p><strong>30.3</strong> Consultation Steps and Indicative reasonable timeframes</p><p><strong>a.</strong> Consultation includes the steps set out below.</p><p><strong>b.</strong> Each step of the consultation process must allow a party to Consultation (including a representative) to genuinely participate in an informed way having</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p>regard for all the circumstances including the complexity of the change proposed, and the need for Employees and their representative to meet with each other and consider and discuss the Employer’s proposal.</p><p><strong>c.</strong> The following table describes the relevant steps for the Consultation process. Step Action 1. Employer provides Change Impact Statement and other written material required by subclause 30.4. Employees and/or Union may request any additional information or material relevant to the proposed change. 2. Written response from Employees and / or Union</p><ol><li><p>Consultation Meeting/s convened</p></li><li><p>Further Employer response (where relevant)</p></li><li><p>Alternative proposal from Employees or Union</p></li><li><p>Employer to consider alternative proposal/s consistent with the obligation to consult and, if applicable, to arrange further meetings with Employees or Union prior to advising outcome of consultation. If an Employer decides the consultation process has finished it shall advise Employees and/or the Union in writing why, and prior to advising an outcome.</p></li></ol><p><strong>d.</strong> The parties will consult on matters covered by this clause without unnecessary delay. Where a party believes that a delay in consultation is unreasonable, the matter may be referred to Fair Work Commission for determination.</p><p><strong>30.4</strong> Change Impact Statement (Step 1) Prior to Consultation required by this clause, the Employer will provide Affected Employee/s and Union with a written Change Impact Statement setting out all relevant information including:</p><p><strong>a.</strong> the details of proposed change;</p><p><strong>b.</strong> the reasons for the proposed change;</p><p><strong>c.</strong> an assessment of how the proposed change will impact on the workload of Employees including occupational health and safety matters.</p><p><strong>d.</strong> the expected benefit of the change;</p><p><strong>e.</strong> measures the Employer is considering that may mitigate or avert the effects of the proposed change;</p><p><strong>f.</strong> if relevant to the proposed change, the existing and proposed position descriptions, including new roles, those of the Affected Employees or managers where reporting lines change;</p><p><strong>g.</strong> the right of an Affected Employee to have a representative including a Union representative at any time during the change process; and</p><p><strong>h.</strong> other written material relevant to the reasons for the proposed change (such as consultant reports), excluding material that is commercial in confidence, or cannot be disclosed under the Health Services Act 1988 or other legislation.</p><p><strong>i.</strong> the expected timing of the proposed change.</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p><strong>j.</strong> the rationale for and details of any proposed redundancy including the number and categories of Employees likely to be affected.</p><p><strong>k.</strong> an assessment of the impacts on quality standards and service outputs.</p><p><strong>l.</strong> Any concerns by an Affected Employee or their representative regarding whether the Change Impact Statement complies with 30.4 will be raised as soon as practicable and where possible before step 2.</p><p><strong>30.5</strong> Employee / Union response (step 2) Following receipt of the Change Impact Statement, Affected Employees and / or the Union may respond in writing to any matter arising from the proposed change.</p><p><strong>30.6</strong> Meetings (step 3)</p><p><strong>a.</strong> As part of Consultation, the Employer will meet with the Employee/s, the Union and other nominated representative/s (if any) to discuss:</p><p><strong>(i)</strong> the proposed change;</p><p><strong>(ii)</strong> proposals to mitigate or avert the impact of the proposed change;</p><p><strong>(iii)</strong> any matter identified in the written response from the Affected Employees and / or the Union;</p><p><strong>(iv)</strong> any other relevant matter raised by the Union;</p><p><strong>b.</strong> To avoid doubt, the ‘first meeting’ at step 3 does not limit the number of meetings for Consultation.</p><p><strong>30.7</strong> Employer response (step 4) The Employer will give prompt and genuine consideration to matters arising from Consultation and will provide a written response to the Affected Employees, Union and (where relevant) other representative/s.</p><p><strong>30.8</strong> Alternative proposal (step 5) The Affected Employee/s, the Union and other representative (where relevant) may submit alternative proposal(s) which will take into account the intended objective and benefits of the proposal. Alternative proposals should be submitted in a timely manner so that unreasonable delay may be avoided.</p><p><strong>30.9</strong> Outcome of Consultation (step 6) The Employer will give prompt and genuine consideration to matters arising from Consultation, including an alternative proposal submitted under sub-clause 30.8 and will advise the Affected Employees, the Union and other nominated representatives (if any) in writing of the outcome of Consultation including:</p><p><strong>a.</strong> whether the Employer intends to proceed with the change proposal;</p><p><strong>b.</strong> any amendment to the change proposal arising from Consultation;</p><p><strong>c.</strong> details of any measures to mitigate or avert the effect of the changes on Affected Employees;</p><p><strong>d.</strong> a summary of how matters that have been raised by Affected Employees, the Union and their representatives including any alternative proposal, have been taken into account; and</p><p><strong>e.</strong> implementation strategy and proposed timeframes of any proposed change.</p><p><strong>30.10</strong> Implementation of change Consultation required by this clause must be completed before the employer implements, or begins to implement, any proposed workplace change.</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p><strong>30.11</strong> Consultation disputes Any dispute regarding the obligations under this clause will be dealt under the Dispute Settling Procedure at <a href="/eba/ebas/mspp/disputes/11-disputes-settling-procedures.html">clause 11</a> of this Agreement.</p><p><strong>30.12</strong> Technological Change – Additional requirements</p><p><strong>a.</strong> When the Employer instructs or commissions Employees (including Employees not covered by this Agreement), consultants or suppliers or any other persons to carry out an investigation of the feasibility of technological change or technological changes arising from organisational change, or personally commences such an investigation, the Employer shall notify in writing:</p><p><strong>(i)</strong> the Union covered by this Agreement; and</p><p><strong>(ii)</strong> in any case where the Employer is able to identify the Employee(s) who may be materially affected in their employment by the change, those Employees, that the investigation is being undertaken, and specify the Employer&#39;s principal objective or objectives of such investigation.</p><p><strong>b.</strong> The Employer shall provide a copy of any report compiled to Employees affected and the Union at the conclusion of an investigation or feasibility investigation.</p><p><strong>c.</strong> During the course of any feasibility investigation, the Employer shall:</p><p><strong>(i)</strong> keep the Employees and Union who have been notified pursuant to this clause informed; and</p><p><strong>(ii)</strong> when requested in writing by such Employees or the Union to do so, consult with them about any change being considered, any material effect which might ensue and alternative proposals which might eliminate or lessen such effects.</p><p>Plain language terms: consult, major workplace change.</p>',81)])])}const d=t(r,[["render",i]]);export{m as __pageData,d as default};
